// ATUALIZADO: Agora lê da propriedade "text" gerada pelo LLM Chain
let rawData = $input.first().json.text;

// ----------------------------
// BLOQUEIO DE NÃO RELEVANTE
// ----------------------------
if (!rawData || rawData.trim().toLowerCase() === "email não relevante") {
  return [
    {
      erro: "EMAIL_NAO_RELEVANTE"
    }
  ];
}

// ----------------------------
// LIMPEZA
// ----------------------------
// Remove blocos de markdown caso a IA ainda insista em mandar
rawData = rawData.replace(/```json|```/g, "").trim();

let parsedData;

try {
  parsedData = JSON.parse(rawData);
} catch (error) {
  return [
    {
      erro: "JSON_INVALIDO_DA_IA",
      raw: rawData
    }
  ];
}

// ----------------------------
// FUNÇÃO UNIVERSAL DE FORMATAÇÃO
// ----------------------------
function formatarData(valor) {
  if (!valor) return { original: null, formatada: "Data não informada" };

  let dateObj;

  if (!isNaN(Number(valor))) {
    let unix = Number(valor);
    if (unix.toString().length === 10) {
      unix = unix * 1000;
    }
    dateObj = new Date(unix);
  } else {
    dateObj = new Date(valor);
  }

  if (isNaN(dateObj.getTime())) {
    return { original: valor, formatada: "Data inválida" };
  }

  const formatter = new Intl.DateTimeFormat('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    hour12: false,
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  });

  const parts = formatter.formatToParts(dateObj);
  const get = (type) => parts.find(p => p.type === type)?.value;

  return {
    original: valor,
    formatada: `${get('hour')}:${get('minute')} ${get('day')}-${get('month')}-${get('year')}`
  };
}

// ----------------------------
// PROCESSAMENTO DAS DATAS
// ----------------------------

// Data do evento (vem da IA)
const evento = formatarData(parsedData.data_evento);

// Data da atualização (vem do Gmail Trigger)
const atualizacao = formatarData($('Gmail Trigger').first().json.internalDate);

// ----------------------------
// RETORNO FINAL
// ----------------------------

return [
  {
    empresa: parsedData.empresa || "Não identificada",
    novo_status: parsedData.novo_status || "Status não definido",
    cargo: parsedData.cargo || "Não informado",
    remetente: parsedData.remetente || null,
    assunto: parsedData.assunto || null,
    resumo: parsedData.resumo || null,

    data_evento_original: evento.original,
    data_evento_formatada: evento.formatada,

    data_atualizacao_original: atualizacao.original,
    data_atualizacao_formatada: atualizacao.formatada
  }
];
